const p = $json;
JSON.stringify({
  model: 'claude-sonnet-4-5',
  max_tokens: 2000,
  messages: [{
    role: 'user',
    content: `You are a world-class product launch video scriptwriter. Write a compelling ${p.duration_seconds}-second launch video script for:

Product: ${p.product_name} by ${p.company_name}
Tagline: ${p.tagline}
Audience: ${p.target_audience}
Problem solved: ${p.problem}
Key features: ${p.key_features.join(', ')}
Stats: ${p.stat_1_number} ${p.stat_1_label} · ${p.stat_2_number} ${p.stat_2_label} · ${p.stat_3_number} ${p.stat_3_label}

Write exactly 6 scenes (each ~15 seconds). Use this EXACT format, nothing else:

SCENE_1_TITLE: [scene name]
SCENE_1_NARRATION: [narrator spoken text, 2-3 sentences, punchy]
SCENE_1_HEADLINE: [large on-screen text, max 6 words]
SCENE_1_SUBTEXT: [supporting on-screen text, max 12 words]
SCENE_1_IMAGE_PROMPT: [DALL-E 3 prompt for cinematic background, ${p.visual_style}, no text in image, under 80 words]

SCENE_2_TITLE: [scene name]
SCENE_2_NARRATION: [...]
SCENE_2_HEADLINE: [...]
SCENE_2_SUBTEXT: [...]
SCENE_2_IMAGE_PROMPT: [...]

...repeat for SCENE_3 through SCENE_6.

Scene guide:
  Scene 1: Powerful brand/problem hook — grab attention in 3 seconds
  Scene 2: Agitate the problem with specific pain points
  Scene 3: Introduce the solution (product name reveal)
  Scene 4: Show 3 key features (one sentence each)
  Scene 5: Social proof — the stats and testimonial
  Scene 6: Clear CTA — ${p.cta_text}

Narration tone: Confident, direct, no fluff. Think Apple keynote energy.`
  }]
})
}}

parameters.jsCode:
const claudeResp = $input.first().json;
const content    = claudeResp.content?.[0]?.text || '';
if (!content) throw new Error('Claude returned empty script. Check ANTHROPIC_API_KEY.');

const params = $('Code: Set Product Parameters').first().json;

function extract(text, key) {
  const m = text.match(new RegExp(`${key}:\\s*(.+)`));
  return m ? m[1].trim() : '';
}

const scenes = [];
for (let i = 1; i <= 6; i++) {
  const title       = extract(content, `SCENE_${i}_TITLE`);
  const narration   = extract(content, `SCENE_${i}_NARRATION`);
  const headline    = extract(content, `SCENE_${i}_HEADLINE`);
  const subtext     = extract(content, `SCENE_${i}_SUBTEXT`);
  const imagePrompt = extract(content, `SCENE_${i}_IMAGE_PROMPT`);
  if (!narration) { console.warn(`Scene ${i} narration missing`); continue; }
  scenes.push({ index: i - 1, title, narration, headline, subtext, imagePrompt });
}

if (scenes.length < 4) throw new Error(`Only ${scenes.length} scenes parsed — check Claude output format`);

// Full narration for TTS (all scenes joined)
const fullNarration = scenes.map(s => s.narration).join(' ');

console.log(`[LaunchVideo] Parsed ${scenes.length} scenes | ${fullNarration.length} chars narration`);

return [{
  json: {
    ...params,
    scenes,
    full_narration:    fullNarration.substring(0, 3000),
    scene_duration:    params.duration_seconds / scenes.length,
    total_duration:    params.duration_seconds,
  }
}];

