parameters.jsCode:
const parsed   = $('Code: Parse Launch Script').first().json;
const prodName = parsed.product_name.toLowerCase().replace(/ /g, '-');
const audioUrl = `${$env.SUPABASE_URL}/storage/v1/object/public/content-audio/launch/${prodName}-launch.mp3`;

console.log(`[LaunchVideo] Audio uploaded. Building ${parsed.scenes.length} scene image prompts`);

// Emit one item per scene for the DALL-E loop
return parsed.scenes.map(scene => ({
  json: {
    // carry everything forward
    ...parsed,
    audio_url:          audioUrl,
    // per-scene fields for DALL-E
    scene_index:        scene.index,
    scene_title:        scene.title,
    scene_narration:    scene.narration,
    scene_headline:     scene.headline,
    scene_subtext:      scene.subtext,
    scene_image_prompt: (scene.imagePrompt + '. Cinematic wide-shot, 16:9 ratio, high quality, no text or typography in the image.').substring(0, 900),
  }
}));

