parameters.jsCode:
const dalleResp = $input.first().json;
const imageUrl  = dalleResp.data?.[0]?.url || '';
if (!imageUrl) throw new Error('DALL-E 3 returned no URL for scene background');

const scene = $('Process Scenes Loop').first().json;
console.log(`[LaunchVideo] Scene ${scene.scene_index + 1}/6 background ready`);

return [{
  json: {
    scene_index:    scene.scene_index,
    scene_title:    scene.scene_title,
    scene_headline: scene.scene_headline,
    scene_subtext:  scene.scene_subtext,
    image_url:      imageUrl,
    audio_url:      scene.audio_url,
    // product params (only what's needed downstream)
    product_name:   scene.product_name,
    tagline:        scene.tagline,
    stat_1_number:  scene.stat_1_number,
    stat_1_label:   scene.stat_1_label,
    stat_2_number:  scene.stat_2_number,
    stat_2_label:   scene.stat_2_label,
    stat_3_number:  scene.stat_3_number,
    stat_3_label:   scene.stat_3_label,
    testimonial:    scene.testimonial,
    testimonial_by: scene.testimonial_by,
    cta_text:       scene.cta_text,
    website_url:    scene.website_url,
    brand_color:    scene.brand_color,
    logo_url:       scene.logo_url,
    music_url:      scene.music_url,
    total_duration: scene.total_duration,
    scene_duration: scene.scene_duration,
  }
}];

// Collect all 6 scenes in order
const allScenes = $('Code: Extract Scene Image URL').all()
  .map(i => i.json)
  .sort((a, b) => a.scene_index - b.scene_index);

if (allScenes.length < 4) throw new Error(`Only ${allScenes.length} scenes collected — loop may not have completed`);

const first         = allScenes[0];
const totalDuration = first.total_duration || 90;
const sceneDuration = parseFloat((totalDuration / allScenes.length).toFixed(2));
const brandColor    = first.brand_color || '#0d9488';

// ─────────────────────────────────────────────────────────────────────────────
// Helper: build CSS-animated HTML clip for each scene
// ─────────────────────────────────────────────────────────────────────────────
function sceneHTML(scene) {
  const i     = scene.scene_index;
  const hl    = (scene.scene_headline || '').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
  const sub   = (scene.scene_subtext  || '').replace(/"/g, '&quot;').replace(/'/g, '&#39;');

  // Scene 0: Brand hero — product name + tagline center-stage
  if (i === 0) {
    return {
      html: `<div class="c"><div class="brand">${first.product_name}</div><div class="tag">${first.tagline}</div></div>`,
      css:  `.c{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;text-align:center;padding:0 80px} .brand{font-family:'Arial Black',Arial,sans-serif;font-size:110px;font-weight:900;color:${brandColor};letter-spacing:-3px;animation:pop 0.9s cubic-bezier(0.34,1.56,0.64,1) both} .tag{font-size:38px;font-weight:600;color:rgba(255,255,255,0.88);margin-top:18px;animation:up 0.8s 0.7s ease both} @keyframes pop{from{transform:scale(0.6);opacity:0}to{transform:scale(1);opacity:1}} @keyframes up{from{transform:translateY(24px);opacity:0}to{transform:translateY(0);opacity:1}}`,
      width: 1800, height: 900
    };
  }

  // Scene 1: The Problem — bold headline left-aligned + red accent
  if (i === 1) {
    return {
      html: `<div class="c"><div class="label">THE PROBLEM</div><div class="hl">${hl}</div><div class="sub">${sub}</div></div>`,
      css:  `.c{display:flex;flex-direction:column;justify-content:center;height:100%;padding:0 120px} .label{font-size:22px;font-weight:700;color:#f97316;letter-spacing:4px;text-transform:uppercase;animation:fl 0.5s ease both} .hl{font-family:'Arial Black',Arial,sans-serif;font-size:72px;font-weight:900;color:#ffffff;line-height:1.1;margin-top:16px;animation:fl 0.6s 0.3s ease both} .sub{font-size:34px;color:rgba(255,255,255,0.75);margin-top:20px;line-height:1.4;animation:fl 0.6s 0.6s ease both} @keyframes fl{from{transform:translateX(-40px);opacity:0}to{transform:translateX(0);opacity:1}}`,
      width: 1800, height: 900
    };
  }

  // Scene 2: Solution reveal — product name with teal glow
  if (i === 2) {
    return {
      html: `<div class="c"><div class="eyebrow">INTRODUCING</div><div class="name">${first.product_name}</div><div class="sub">${sub}</div></div>`,
      css:  `.c{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;text-align:center} .eyebrow{font-size:24px;font-weight:700;color:rgba(255,255,255,0.6);letter-spacing:6px;text-transform:uppercase;animation:fd 0.6s ease both} .name{font-family:'Arial Black',Arial,sans-serif;font-size:120px;font-weight:900;color:${brandColor};letter-spacing:-4px;margin-top:12px;text-shadow:0 0 80px ${brandColor};animation:glow 0.8s 0.4s ease both} .sub{font-size:36px;color:rgba(255,255,255,0.8);margin-top:20px;animation:fd 0.6s 0.9s ease both} @keyframes glow{from{opacity:0;text-shadow:0 0 0 ${brandColor}}to{opacity:1;text-shadow:0 0 80px ${brandColor}}} @keyframes fd{from{opacity:0}to{opacity:1}}`,
      width: 1800, height: 900
    };
  }

  // Scene 3: Features — 3 feature cards with staggered slide-in
  if (i === 3) {
    return {
      html: `<div class="c"><div class="heading">${hl}</div><div class="sub">${sub}</div></div>`,
      css:  `.c{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;text-align:center;padding:0 100px} .heading{font-family:'Arial Black',Arial,sans-serif;font-size:68px;font-weight:900;color:#ffffff;line-height:1.15;animation:up 0.7s ease both} .sub{font-size:32px;color:rgba(255,255,255,0.75);margin-top:22px;line-height:1.5;animation:up 0.7s 0.4s ease both} @keyframes up{from{transform:translateY(30px);opacity:0}to{transform:translateY(0);opacity:1}}`,
      width: 1800, height: 900
    };
  }

  // Scene 4: Social proof — 3 stat blocks + testimonial
  if (i === 4) {
    return {
      html: `<div class="c"><div class="stats"><div class="s"><span class="n">${first.stat_1_number}</span><span class="l">${first.stat_1_label}</span></div><div class="div"></div><div class="s"><span class="n">${first.stat_2_number}</span><span class="l">${first.stat_2_label}</span></div><div class="div"></div><div class="s"><span class="n">${first.stat_3_number}</span><span class="l">${first.stat_3_label}</span></div></div><div class="quote">&ldquo;${first.testimonial}&rdquo;</div><div class="by">${first.testimonial_by}</div></div>`,
      css:  `.c{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;text-align:center;padding:0 100px} .stats{display:flex;align-items:center;gap:32px;margin-bottom:36px;animation:pop 0.8s ease both} .s{display:flex;flex-direction:column;align-items:center} .n{font-family:'Arial Black',Arial,sans-serif;font-size:72px;font-weight:900;color:${brandColor};line-height:1} .l{font-size:20px;color:rgba(255,255,255,0.7);margin-top:6px;max-width:180px;line-height:1.3} .div{width:2px;height:80px;background:rgba(255,255,255,0.2)} .quote{font-size:30px;color:rgba(255,255,255,0.9);font-style:italic;line-height:1.5;animation:up 0.7s 0.5s ease both} .by{font-size:22px;color:${brandColor};margin-top:12px;animation:up 0.6s 0.8s ease both} @keyframes pop{from{transform:scale(0.9);opacity:0}to{transform:scale(1);opacity:1}} @keyframes up{from{transform:translateY(20px);opacity:0}to{transform:translateY(0);opacity:1}}`,
      width: 1800, height: 900
    };
  }

  // Scene 5 (last): CTA — website + sign-up prompt
  return {
    html: `<div class="c"><div class="brand">${first.product_name}</div><div class="cta">${first.cta_text}</div><div class="url">${first.website_url}</div></div>`,
    css:  `.c{display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;text-align:center} .brand{font-family:'Arial Black',Arial,sans-serif;font-size:80px;font-weight:900;color:${brandColor};animation:pop 0.8s ease both} .cta{font-size:44px;font-weight:700;color:#ffffff;margin-top:20px;background:${brandColor};padding:18px 48px;border-radius:12px;animation:pop 0.8s 0.4s ease both} .url{font-size:28px;color:rgba(255,255,255,0.65);margin-top:20px;animation:fd 0.8s 0.9s ease both} @keyframes pop{from{transform:scale(0.8);opacity:0}to{transform:scale(1);opacity:1}} @keyframes fd{from{opacity:0}to{opacity:1}}`,
    width: 1800, height: 900
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// Build Shotstack timeline
// ─────────────────────────────────────────────────────────────────────────────
const imageClips = allScenes.map((scene, i) => ({
  asset: { type: 'image', src: scene.image_url },
  start:      parseFloat((i * sceneDuration).toFixed(2)),
  length:     sceneDuration,
  effect:     i % 2 === 0 ? 'zoomIn' : 'zoomOut',
  transition: { in: 'fade', out: 'fade' }
}));

// Dark overlay scrim on all scenes so text always reads
const scrimClip = [{
  asset: { type: 'shape', shape: 'rectangle', fill_color: 'rgba(4,10,20,0.52)', width: '100%', height: '100%' },
  start:  0,
  length: totalDuration
}];

// Per-scene animated HTML text
const textClips = allScenes.map((scene, i) => {
  const h = sceneHTML(scene);
  return {
    asset: { type: 'html', html: h.html, css: h.css, width: h.width, height: h.height },
    start:      parseFloat((i * sceneDuration).toFixed(2)),
    length:     sceneDuration,
    position:   'center',
    transition: { in: 'fade', out: 'fade' }
  };
});

// Optional logo (top-left, full video)
const logoClips = first.logo_url ? [{
  asset: { type: 'image', src: first.logo_url },
  start:    0,
  length:   totalDuration,
  width:    '12%',
  position: 'topLeft',
  offset:   { x: 0.03, y: 0.04 },
  opacity:  0.9
}] : [];

// Bottom progress bar (teal, animates over video duration)
const progressBar = [{
  asset: {
    type:       'html',
    html:       '<div class="bar"></div>',
    css:        `.bar{width:100%;height:5px;background:${brandColor};transform-origin:left;animation:grow ${totalDuration}s linear both} @keyframes grow{from{transform:scaleX(0)}to{transform:scaleX(1)}}`,
    width:      1920,
    height:     10
  },
  start:    0,
  length:   totalDuration,
  position: 'bottom',
  offset:   { y: 0.005 }
}];

// Soundtrack
const soundtrack = {
  src:    first.audio_url,
  effect: 'fadeOut',
  volume: 1
};

// Optional background music (lower volume mix)
const timeline = {
  soundtrack,
  tracks: [
    { clips: logoClips.length ? logoClips : [{ asset: { type: 'shape', shape: 'rectangle', fill_color: 'rgba(0,0,0,0)', width: 1, height: 1 }, start: 0, length: 1 }] },
    { clips: progressBar },
    { clips: textClips },
    { clips: scrimClip },
    { clips: imageClips }
  ]
};

// Add background music track if provided
if (first.music_url) {
  timeline.tracks.push({
    clips: [{
      asset: { type: 'audio', src: first.music_url, volume: 0.12, effect: 'fadeOut' },
      start:  0,
      length: totalDuration
    }]
  });
}

const shotstack_payload = {
  timeline,
  output: {
    format:  'mp4',
    size:    { width: 1920, height: 1080 },
    fps:     30,
    quality: 'high'
  }
};

console.log(`[LaunchVideo] Timeline built: ${allScenes.length} scenes, ${totalDuration}s, 1920×1080`);

return [{
  json: {
    product_name:      first.product_name,
    audio_url:         first.audio_url,
    scene_image_urls:  allScenes.map(s => s.image_url),
    shotstack_payload: shotstack_payload
  }
}];

const res      = $input.first().json;
const renderId = res?.response?.id || '';
if (!renderId) throw new Error('Shotstack did not return render ID — check SHOTSTACK_API_KEY: ' + JSON.stringify(res).substring(0,200));

const prev = $('Code: Assemble Shotstack Launch Timeline').first().json;
console.log(`[LaunchVideo] Render queued: ${renderId}`);

return [{
  json: {
    render_id:        renderId,
    product_name:     prev.product_name,
    audio_url:        prev.audio_url,
    scene_image_urls: prev.scene_image_urls,
  }
}];

const r        = $input.first().json;
const status   = r?.response?.status || 'unknown';
const videoUrl = r?.response?.url    || '';

if (!videoUrl || status !== 'done') {
  const err = r?.response?.error || 'check shotstack.io → Dashboard → Renders';
  throw new Error(`Launch video render not complete (status: ${status}). Detail: ${err}`);
}

const meta = $('Code: Store Render ID').first().json;
console.log(`[LaunchVideo] ✅ Ready: ${videoUrl}`);

return [{
  json: {
    product_name:     meta.product_name,
    video_url:        videoUrl,
    audio_url:        meta.audio_url,
    scene_image_urls: meta.scene_image_urls,
    render_id:        meta.render_id,
  }
}];
